  1→import React, { useCallback, useEffect, useRef, useState } from "react";
  2→import { RichTextPlugin } from "@lexical/react/LexicalRichTextPlugin";
  3→import { ContentEditable } from "@lexical/react/LexicalContentEditable";
  4→import { HistoryPlugin } from "@lexical/react/LexicalHistoryPlugin";
  5→import { OnChangePlugin } from "@lexical/react/LexicalOnChangePlugin";
  6→import { useLexicalComposerContext } from "@lexical/react/LexicalComposerContext";
  7→import { LexicalErrorBoundary } from "@lexical/react/LexicalErrorBoundary";
  8→import { ListPlugin } from "@lexical/react/LexicalListPlugin";
  9→import { CheckListPlugin } from "@lexical/react/LexicalCheckListPlugin";
 10→import { HorizontalRulePlugin } from "@lexical/react/LexicalHorizontalRulePlugin";
 11→import { LinkPlugin } from "@lexical/react/LexicalLinkPlugin";
 12→import { MarkdownShortcutPlugin } from "@lexical/react/LexicalMarkdownShortcutPlugin";
 13→import { TRANSFORMERS } from "@lexical/markdown";
 14→import { CodeHighlightPlugin } from "./plugins/CodeHighlightPlugin";
 15→import { AutoLinkPlugin } from "./plugins/AutoLinkPlugin";
 16→import FloatingLinkEditor from "./plugins/FloatingLinkEditor";
 17→import FloatingSelectionToolbar from "./plugins/FloatingSelectionToolbar";
 18→import PasteImagePlugin from "./plugins/PasteImagePlugin";
 19→import ImagePlugin from "./nodes/Plugins/ImagePlugin";
 20→import MentionPlugin from "./nodes/Plugins/MentionPlugin";
 21→
 22→import { saveJournal, saveDraft, publishDraft } from "../../../../API/Api";
 23→import { useAuth } from "../../../Context/useAuth";
 24→import { useQueryClient } from '@tanstack/react-query';
 25→
 26→import { BarLoader } from "react-spinners";
 27→import { $getRoot } from "lexical";
 28→
 29→
 30→class ErrorBoundary extends React.Component {
 31→  state = { error: null };
 32→  static getDerivedStateFromError(error) {
 33→    return { error };
 34→  }
 35→  render() {
 36→    if (this.state.error) {
 37→      return <div>Error: {this.state.error.message}</div>;
 38→    }
 39→    return this.props.children;
 40→  }
 41→}
 42→
 43→/* theme for mapping css classes to lexical rols */
 44→const theme = {
 45→    paragraph: 'editor-paragraph',
 46→    heading: 'editor-heading',
 47→}
 48→
 49→const formatTimeAgo = (date) => {
 50→    if (!date) return '';
 51→    const seconds = Math.floor((Date.now() - date.getTime()) / 1000);
 52→    if (seconds < 60) return 'just now';
 53→    const minutes = Math.floor(seconds / 60);
 54→    if (minutes < 60) return `${minutes}m ago`;
 55→    const hours = Math.floor(minutes / 60);
 56→    return `${hours}h ago`;
 57→};
 58→
 59→const EditorInner = ({title, onclose, onCloseOnSave, addUploadImagesPath, setWordCount, wordCount, promptId = null, draftId = null, onDraftIdCreated, editorStateRef}) => {
 60→    const [editor] = useLexicalComposerContext();
 61→    const [editorState, setEditorState] = useState(null);
 62→    const [hasContent, setHasContent] = useState(false);
 63→    const [isSending, setIsSending] = useState(false);
 64→
 65→    // Draft state
 66→    const draftIdRef = useRef(draftId);
 67→    const [saveStatus, setSaveStatus] = useState(draftId ? 'saved' : null); // null | 'saving' | 'saved' | 'unsaved'
 68→    const [lastSavedAt, setLastSavedAt] = useState(draftId ? new Date() : null);
 69→    const [hasChanges, setHasChanges] = useState(false);
 70→    const saveTimerRef = useRef(null);
 71→    const [, forceUpdate] = useState(0);
 72→
 73→    // Expose saveTimerRef to parent so it can cancel pending auto-saves
 74→    useEffect(() => {
 75→        if (editorStateRef) {
 76→            editorStateRef.current.saveTimerRef = saveTimerRef;
 77→        }
 78→    }, [editorStateRef]);
 79→
 80→    const {session, user} = useAuth();
 81→
 82→    const queryClient = useQueryClient();
 83→    const userId = user?.userData?.[0]?.id || null;
 84→
 85→    // Keep draftIdRef in sync
 86→    useEffect(() => {
 87→        draftIdRef.current = draftId;
 88→    }, [draftId]);
 89→
 90→    // Tick the "saved X ago" display every 30s
 91→    useEffect(() => {
 92→        if (!lastSavedAt) return;
 93→        const interval = setInterval(() => forceUpdate(n => n + 1), 30000);
 94→        return () => clearInterval(interval);
 95→    }, [lastSavedAt]);
 96→
 97→    const invalidateCreatedJournalQueries = useCallback(async() => {
 98→        const invalidations = [
 99→            queryClient.invalidateQueries({queryKey: ['journals'], refetchType: 'active'}),
100→            queryClient.invalidateQueries({queryKey: ['journals-following'], refetchType: 'active'}),
101→            queryClient.invalidateQueries({queryKey: ['journals-for-you'], refetchType: 'active'}),
102→            queryClient.invalidateQueries({queryKey: ['journals-search'], refetchType: 'active'}),
103→            queryClient.invalidateQueries({queryKey: ['journals-suggestions'], refetchType: 'active'}),
104→            queryClient.invalidateQueries({queryKey: ['journal-drafts'], refetchType: 'active'}),
105→        ];
106→
107→        if(userId){
108→            invalidations.push(
109→                queryClient.invalidateQueries({queryKey: ['userJournals', userId], refetchType: 'active'}),
110→                queryClient.invalidateQueries({queryKey: ['streak', userId], refetchType: 'active'})
111→            );
112→        }
113→
114→        await Promise.allSettled(invalidations);
115→    }, [queryClient, userId]);
116→
117→    const handleSaveDraft = useCallback(async(showFeedback = true) => {
118→        if (!editorState || !session?.access_token) return;
119→        if (showFeedback) setSaveStatus('saving');
120→
121→        try {
122→            const result = await saveDraft(session.access_token, {
123→                content: editorState,
124→                title: title || '',
125→                draftId: draftIdRef.current || null,
126→                prompt_id: promptId || null,
127→            });
128→
129→            if (result?.id && !draftIdRef.current) {
130→                draftIdRef.current = result.id;
131→                if (onDraftIdCreated) onDraftIdCreated(result.id);
132→            }
133→
134→            setHasChanges(false);
135→            setSaveStatus('saved');
136→            setLastSavedAt(new Date());
137→            if (editorStateRef) {
138→                editorStateRef.current = { ...editorStateRef.current, hasChanges: false };
139→            }
140→            queryClient.invalidateQueries({queryKey: ['journal-drafts'], refetchType: 'active'});
141→        } catch (error) {
142→            console.error('Failed to save draft:', error);
143→            setSaveStatus('unsaved');
144→        }
145→    }, [editorState, session?.access_token, title, promptId, onDraftIdCreated, queryClient]);
146→
147→    // Auto-save every 30 seconds when there are changes
148→    useEffect(() => {
149→        if (!hasChanges || !editorState) return;
150→
151→        if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
152→        saveTimerRef.current = setTimeout(() => {
153→            handleSaveDraft(false);
154→        }, 30000);
155→
156→        return () => {
157→            if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
158→        };
159→    }, [editorState, hasChanges, handleSaveDraft]);
160→
161→    const handleClickPublish = async(e, title) => {
162→        e.stopPropagation();
163→        setIsSending(true);
164→
165→        try {
166→            // If we have a draft, publish it
167→            if (draftIdRef.current) {
168→                // Save latest content first
169→                await saveDraft(session.access_token, {
170→                    content: editorState,
171→                    title: title || '',
172→                    draftId: draftIdRef.current,
173→                });
174→
175→                await publishDraft(session.access_token, draftIdRef.current);
176→            } else {
177→                // Direct publish (no draft exists) — use existing save-journal flow
178→                const formdata = new FormData();
179→                if(title && editorState){
180→                    formdata.append('title', title);
181→                    formdata.append('content', editorState);
182→                }
183→                if(promptId){
184→                    formdata.append('prompt_id', promptId);
185→                }
186→                await saveJournal(session?.access_token, formdata);
187→            }
188→
189→            await invalidateCreatedJournalQueries();
190→            setHasContent(false);
191→            onCloseOnSave();
192→            addUploadImagesPath([]);
193→        } catch (error) {
194→            console.error("Error publishing journal:", error);
195→        } finally {
196→            setIsSending(false);
197→        }
198→    }
199→
200→    const onchange = useCallback((state) => {
201→        const jsonb = JSON.stringify(state.toJSON());
202→        setEditorState(jsonb)
203→        setHasChanges(true);
204→        if (saveStatus === 'saved') setSaveStatus('unsaved');
205→
206→        state.read(() => {
207→            const root = $getRoot();
208→
209→            const children = root.getChildren();
210→
211→            const hasEnoughParagraphNodes = children.length > 1
212→            const hasParargraphSize = children[0]?.__size > 0
213→
214→            const hasContent = hasParargraphSize || hasEnoughParagraphNodes
215→            setHasContent(hasContent);
216→
217→            // Calculate word count
218→            const text = root.getTextContent().trim();
219→            const words = text ? text.split(/\s+/).length : 0;
220→            setWordCount(words);
221→
222→            // Expose state to parent via ref
223→            if (editorStateRef) {
224→                editorStateRef.current = { ...editorStateRef.current, hasChanges: true, hasContent, editorState: jsonb, title };
225→            }
226→        })
227→    }, [setWordCount, saveStatus])
228→
229→    const renderSaveStatus = () => {
230→        if (!saveStatus) return null;
231→
232→        let statusText = '';
233→        let statusClass = 'editor-save-status';
234→
235→        switch (saveStatus) {
236→            case 'saving':
237→                statusText = 'Saving...';
238→                statusClass += ' editor-save-status--saving';
239→                break;
240→            case 'saved':
241→                statusText = lastSavedAt ? `Saved ${formatTimeAgo(lastSavedAt)}` : 'Saved';
242→                statusClass += ' editor-save-status--saved';
243→                break;
244→            case 'unsaved':
245→                statusText = 'Unsaved changes';
246→                statusClass += ' editor-save-status--unsaved';
247→                break;
248→            default:
249→                return null;
250→        }
251→
252→        return <span className={statusClass}>{statusText}</span>;
253→    };
254→
255→    return(
256→        <>
257→        {/* Bar loader directly under toolbar */}
258→        <div className="editor-loader-wrapper">
259→            {isSending && (
260→                <BarLoader loading={isSending} width={'100%'} height={3} color="var(--accent-purple)" speedMultiplier={0.7}/>
261→            )}
262→        </div>
263→
264→        {/* Editor content area */}
265→        <div className="editor-shell">
266→            <RichTextPlugin
267→            contentEditable={
268→            <ContentEditable
269→            className="editor-input"
270→            aria-placeholder="Write your thoughts here..."
271→            placeholder={<div className="editor-placeholder">Write your thoughts here...</div>}/>
272→            }
273→            ErrorBoundary={LexicalErrorBoundary}
274→            />
275→
276→            <ImagePlugin addUploadedImagePath={addUploadImagesPath}/>
277→            <MentionPlugin/>
278→            <HistoryPlugin/>
279→            <OnChangePlugin onChange={onchange}/>
280→            <ListPlugin/>
281→            <CheckListPlugin/>
282→            <HorizontalRulePlugin/>
283→            <LinkPlugin validateUrl={(url) => {
284→                try { return Boolean(new URL(url)); } catch { return false; }
285→            }}/>
286→            <AutoLinkPlugin/>
287→            <CodeHighlightPlugin/>
288→            <MarkdownShortcutPlugin transformers={TRANSFORMERS}/>
289→            <FloatingLinkEditor/>
290→            <FloatingSelectionToolbar/>
291→            <PasteImagePlugin addUploadedImagePath={addUploadImagesPath} token={session?.access_token}/>
292→
293→        </div>
294→
295→        {/* Footer: word count + save status + buttons */}
296→        <div className='editor-footer'>
297→            <div className="editor-footer-left">
298→                <span className="editor-word-count">
299→                    {wordCount} {wordCount === 1 ? 'word' : 'words'}
300→                </span>
301→                {renderSaveStatus()}
302→            </div>
303→            <div className="editor-footer-actions">
304→                <button
305→                    disabled={!hasContent || isSending}
306→                    onClick={() => handleSaveDraft(true)}
307→                    className={hasContent && !isSending ? 'editor-draft-bttn' : 'editor-draft-bttn-disabled'}
308→                >
309→                    Save Draft
310→                </button>
311→                <button
312→                    disabled={!title || !hasContent || isSending}
313→                    onClick={(e) => handleClickPublish(e, title)}
314→                    className={title && hasContent && !isSending ? 'editor-save-bttn' : 'editor-save-bttn-disabled'}
315→                >
316→                    Publish
317→                </button>
318→            </div>
319→        </div>
320→        </>
321→    )
322→}
323→
324→export default EditorInner;
325→

  1→import { useCallback, useEffect, useRef, useState } from "react";
  2→
  3→import {
  4→  FORMAT_TEXT_COMMAND,
  5→  FORMAT_ELEMENT_COMMAND,
  6→  UNDO_COMMAND,
  7→  REDO_COMMAND,
  8→  CAN_UNDO_COMMAND,
  9→  CAN_REDO_COMMAND,
 10→  COMMAND_PRIORITY_LOW,
 11→  $getSelection,
 12→  $isRangeSelection,
 13→  $createParagraphNode,
 14→} from "lexical";
 15→
 16→import { $createHeadingNode, $isHeadingNode, $createQuoteNode, $isQuoteNode } from "@lexical/rich-text";
 17→import { $getSelectionStyleValueForProperty, $patchStyleText, $setBlocksType } from "@lexical/selection";
 18→import { useLexicalComposerContext } from "@lexical/react/LexicalComposerContext";
 19→import { $isListNode, INSERT_UNORDERED_LIST_COMMAND, INSERT_ORDERED_LIST_COMMAND, INSERT_CHECK_LIST_COMMAND, REMOVE_LIST_COMMAND } from "@lexical/list";
 20→import { $isCodeNode, $createCodeNode } from "@lexical/code";
 21→import { $isLinkNode, TOGGLE_LINK_COMMAND, $toggleLink } from "@lexical/link";
 22→import { INSERT_HORIZONTAL_RULE_COMMAND } from "@lexical/react/LexicalHorizontalRuleNode";
 23→import { INSERT_IMAGE_COMMAND } from "./nodes/ImageNode";
 24→import { saveJournalImage } from "../../../../API/Api";
 25→import { useAuth } from "../../../Context/useAuth";
 26→
 27→const DEFAULT_ACTIVE_STATES = {
 28→    bold: false,
 29→    italic: false,
 30→    underline: false,
 31→    strikethrough: false,
 32→    inlineCode: false,
 33→    heading: null,
 34→    quote: false,
 35→    alignment: 'left',
 36→    textColor: '',
 37→    highlightColor: '',
 38→    listType: null, // 'bullet' | 'number' | 'check' | null
 39→    isCodeBlock: false,
 40→    isLink: false,
 41→    canUndo: false,
 42→    canRedo: false,
 43→};
 44→
 45→const ToolBar = ({addUploadedImagePath}) =>{
 46→    const [editor] = useLexicalComposerContext();
 47→    const {session} = useAuth();
 48→    const colorPickerRef = useRef(null);
 49→
 50→    // Active state tracking
 51→    const [activeStates, setActiveStates] = useState(DEFAULT_ACTIVE_STATES);
 52→
 53→    const [showTextColorPicker, setShowTextColorPicker] = useState(false);
 54→    const [showHighlightColorPicker, setShowHighlightColorPicker] = useState(false);
 55→
 56→    const COLOR_PALETTE = [
 57→        { label: 'Default', value: null },
 58→        { label: 'Black', value: '#000000' },
 59→        { label: 'Dark Gray', value: '#4d4d4d' },
 60→        { label: 'Gray', value: '#888888' },
 61→        { label: 'Light Gray', value: '#bfbfbf' },
 62→        { label: 'Red', value: '#f44336' },
 63→        { label: 'Pink', value: '#e91e63' },
 64→        { label: 'Purple', value: '#9c27b0' },
 65→        { label: 'Deep Purple', value: '#673ab7' },
 66→        { label: 'Indigo', value: '#3f51b5' },
 67→        { label: 'Blue', value: '#2196f3' },
 68→        { label: 'Light Blue', value: '#03a9f4' },
 69→        { label: 'Cyan', value: '#00bcd4' },
 70→        { label: 'Teal', value: '#009688' },
 71→        { label: 'Green', value: '#4caf50' },
 72→        { label: 'Light Green', value: '#8bc34a' },
 73→        { label: 'Lime', value: '#cddc39' },
 74→        { label: 'Yellow', value: '#ffeb3b' },
 75→        { label: 'Amber', value: '#ffc107' },
 76→        { label: 'Orange', value: '#ff9800' },
 77→        { label: 'Deep Orange', value: '#ff5722' },
 78→        { label: 'Brown', value: '#795548' },
 79→        { label: 'Blue Gray', value: '#607d8b' },
 80→    ];
 81→
 82→    const toCompactRgb = (value) => {
 83→        if (!value) return '';
 84→        return value.toLowerCase().replace(/\s+/g, '');
 85→    };
 86→
 87→    const normalizeColor = (value) => {
 88→        if (!value) return '';
 89→        const trimmed = value.trim().toLowerCase();
 90→        if (!trimmed.startsWith('#')) {
 91→            return toCompactRgb(trimmed);
 92→        }
 93→
 94→        let hex = trimmed.slice(1);
 95→        if (hex.length === 3) {
 96→            hex = hex.split('').map((char) => `${char}${char}`).join('');
 97→        }
 98→        if (hex.length !== 6) {
 99→            return trimmed;
100→        }
101→
102→        const r = parseInt(hex.slice(0, 2), 16);
103→        const g = parseInt(hex.slice(2, 4), 16);
104→        const b = parseInt(hex.slice(4, 6), 16);
105→
106→        return `rgb(${r},${g},${b})`;
107→    };
108→
109→    const isPaletteColorActive = (activeValue, paletteValue) => {
110→        const normalizedActive = normalizeColor(activeValue);
111→        if (!paletteValue) {
112→            return !normalizedActive;
113→        }
114→        return normalizedActive === normalizeColor(paletteValue);
115→    };
116→
117→    // Register undo/redo command listeners
118→    useEffect(() => {
119→        const unregisterUndo = editor.registerCommand(
120→            CAN_UNDO_COMMAND,
121→            (payload) => {
122→                setActiveStates((prev) => ({ ...prev, canUndo: payload }));
123→                return false;
124→            },
125→            COMMAND_PRIORITY_LOW,
126→        );
127→        const unregisterRedo = editor.registerCommand(
128→            CAN_REDO_COMMAND,
129→            (payload) => {
130→                setActiveStates((prev) => ({ ...prev, canRedo: payload }));
131→                return false;
132→            },
133→            COMMAND_PRIORITY_LOW,
134→        );
135→        return () => {
136→            unregisterUndo();
137→            unregisterRedo();
138→        };
139→    }, [editor]);
140→
141→    // Register update listener for active state detection
142→    useEffect(() => {
143→        return editor.registerUpdateListener(({ editorState }) => {
144→            editorState.read(() => {
145→                const selection = $getSelection();
146→                if (!$isRangeSelection(selection)) {
147→                    setActiveStates((prev) => ({
148→                        ...DEFAULT_ACTIVE_STATES,
149→                        canUndo: prev.canUndo,
150→                        canRedo: prev.canRedo,
151→                    }));
152→                    return;
153→                }
154→
155→                const bold = selection.hasFormat('bold');
156→                const italic = selection.hasFormat('italic');
157→                const underline = selection.hasFormat('underline');
158→                const strikethrough = selection.hasFormat('strikethrough');
159→                const inlineCode = selection.hasFormat('code');
160→
161→                const anchorNode = selection.anchor.getNode();
162→                const parent = anchorNode.getParent();
163→
164→                let element;
165→                try {
166→                    element = anchorNode.getKey() === 'root'
167→                        ? anchorNode
168→                        : anchorNode.getTopLevelElement() || anchorNode.getTopLevelElementOrThrow();
169→                } catch {
170→                    element = null;
171→                }
172→
173→                let heading = null;
174→                let quote = false;
175→                let alignment = 'left';
176→                let listType = null;
177→                let isCodeBlock = false;
178→                let isLink = false;
179→
180→                if (element) {
181→                    if ($isHeadingNode(element)) {
182→                        heading = element.getTag();
183→                    }
184→                    if ($isQuoteNode(element)) {
185→                        quote = true;
186→                    }
187→                    if ($isListNode(element)) {
188→                        const type = element.getListType();
189→                        listType = type === 'bullet' ? 'bullet' : type === 'number' ? 'number' : type === 'check' ? 'check' : null;
190→                    }
191→                    if ($isCodeNode(element)) {
192→                        isCodeBlock = true;
193→                    }
194→                    const formatType = element.getFormatType?.();
195→                    if (formatType) {
196→                        alignment = formatType;
197→                    }
198→                }
199→
200→                // Check for list type on parent (listitem → list)
201→                if (!listType && parent) {
202→                    const grandParent = parent.getParent?.();
203→                    if (grandParent && $isListNode(grandParent)) {
204→                        const type = grandParent.getListType();
205→                        listType = type === 'bullet' ? 'bullet' : type === 'number' ? 'number' : type === 'check' ? 'check' : null;
206→                    }
207→                }
208→
209→                // Check for link
210→                if ($isLinkNode(parent)) {
211→                    isLink = true;
212→                } else if ($isLinkNode(anchorNode)) {
213→                    isLink = true;
214→                }
215→
216→                const textColor = $getSelectionStyleValueForProperty(selection, 'color', '');
217→                const highlightColor = $getSelectionStyleValueForProperty(selection, 'background-color', '');
218→
219→                setActiveStates((prev) => ({
220→                    bold,
221→                    italic,
222→                    underline,
223→                    strikethrough,
224→                    inlineCode,
225→                    heading,
226→                    quote,
227→                    alignment,
228→                    textColor,
229→                    highlightColor,
230→                    listType,
231→                    isCodeBlock,
232→                    isLink,
233→                    canUndo: prev.canUndo,
234→                    canRedo: prev.canRedo,
235→                }));
236→            });
237→        });
238→    }, [editor]);
239→
240→    useEffect(() => {
241→        const handleClickOutside = (event) => {
242→            if (!colorPickerRef.current) return;
243→            if (!colorPickerRef.current.contains(event.target)) {
244→                setShowTextColorPicker(false);
245→                setShowHighlightColorPicker(false);
246→            }
247→        };
248→        document.addEventListener('mousedown', handleClickOutside);
249→        return () => document.removeEventListener('mousedown', handleClickOutside);
250→    }, []);
251→
252→
253→    const applyTextFormat = (format) => {
254→        editor.dispatchCommand(FORMAT_TEXT_COMMAND, format)
255→    }
256→
257→    const applyTextStyle = useCallback((styles) => {
258→        const sanitizedStyles = Object.fromEntries(
259→            Object.entries(styles).map(([key, value]) => [key, value ?? ''])
260→        );
261→        editor.update(() => {
262→            const selection = $getSelection();
263→            if ($isRangeSelection(selection)) {
264→                $patchStyleText(selection, sanitizedStyles);
265→            }
266→        });
267→    }, [editor]);
268→
269→    //heading node (H1, H2, H3)
270→    const setHeading = (tag) => {
271→        editor.update(() => {
272→            const selection = $getSelection();
273→            if ($isRangeSelection(selection)) {
274→                const anchorNode = selection.anchor.getNode();
275→
276→                let element;
277→                try {
278→                    element = anchorNode.getKey() === 'root'
279→                        ? anchorNode
280→                        : anchorNode.getTopLevelElement() || anchorNode.getTopLevelElementOrThrow();
281→                } catch (e) {
282→                    console.error('Could not get top level element:', e);
283→                    return;
284→                }
285→
286→                if (!element) return;
287→
288→                const type = typeof element.getType === 'function' ? element.getType() : null;
289→
290→                if (type && type !== "paragraph" && type !== "heading" && type !== "root") {
291→                    return;
292→                }
293→
294→                const isActive = $isHeadingNode(element) && element.getTag() === tag;
295→
296→                $setBlocksType(selection, () =>
297→                    isActive ? $createParagraphNode() : $createHeadingNode(tag)
298→                );
299→            }
300→        })
301→    }
302→
303→    //align element
304→    const setAlignment = (value) => {
