308→    //quote block (toggle)
309→    const setQuote = () => {
310→        editor.update(() => {
311→            const selection = $getSelection();
312→            if ($isRangeSelection(selection)) {
313→                const anchorNode = selection.anchor.getNode();
314→
315→                let element;
316→                try {
317→                    element = anchorNode.getKey() === 'root'
318→                        ? anchorNode
319→                        : anchorNode.getTopLevelElement() || anchorNode.getTopLevelElementOrThrow();
320→                } catch (e) {
321→                    console.error('Could not get top level element:', e);
322→                    return;
323→                }
324→
325→                if (!element) return;
326→
327→                const type = typeof element.getType === 'function' ? element.getType() : null;
328→                if (type && type !== "paragraph" && type !== "heading" && type !== "quote" && type !== "root") {
329→                    return;
330→                }
331→
332→                const isActive = $isQuoteNode(element);
333→
334→                $setBlocksType(selection, () =>
335→                    isActive ? $createParagraphNode() : $createQuoteNode()
336→                );
337→            }
338→        })
339→    }
340→
