342→    const toggleList = (type) => {
343→        if (activeStates.listType === type) {
344→            editor.dispatchCommand(REMOVE_LIST_COMMAND, undefined);
345→        } else {
346→            switch (type) {
347→                case 'bullet':
348→                    editor.dispatchCommand(INSERT_UNORDERED_LIST_COMMAND, undefined);
349→                    break;
350→                case 'number':
351→                    editor.dispatchCommand(INSERT_ORDERED_LIST_COMMAND, undefined);
352→                    break;
353→                case 'check':
354→                    editor.dispatchCommand(INSERT_CHECK_LIST_COMMAND, undefined);
355→                    break;
